import { describe, expect, it } from 'vitest';

import {
  CostLedger,
  FRF,
  GROUNDING_TRITON,
  MonsterCache,
  PLEROMATIC_CLOSURE,
  SHARED_UNIT,
  SovereignJudge,
  TRIPLE_POINT,
  TRITON_STRETCH_FACTOR,
  groundingTritonSnapshot,
} from '../src/pleromatic-core';

describe('Pleromatic core constants', () => {
  it('Pleromatic Closure is 10', () => {
    expect(PLEROMATIC_CLOSURE).toBe(10);
  });

  it('Shared unit is 1', () => {
    expect(SHARED_UNIT).toBe(1);
  });

  it('Triton-stretch factor is 3', () => {
    expect(TRITON_STRETCH_FACTOR).toBe(3);
  });

  it('Triple point is (10, 1)', () => {
    expect(TRIPLE_POINT).toEqual({ closureValue: 10, sharedUnit: 1 });
  });
});

describe('Grounding Triton', () => {
  it('has three nodes with pairwise unit equality', () => {
    expect(GROUNDING_TRITON.math.unit).toBe(1);
    expect(GROUNDING_TRITON.physics.unit).toBe(1);
    expect(GROUNDING_TRITON.moonshine.unit).toBe(1);
  });

  it('has distinct Probe/Return/Verify roles', () => {
    expect(GROUNDING_TRITON.math.role).toBe('probe');
    expect(GROUNDING_TRITON.physics.role).toBe('return');
    expect(GROUNDING_TRITON.moonshine.role).toBe('verify');
  });

  it('all nodes close at 10', () => {
    expect(GROUNDING_TRITON.math.closureValue).toBe(10);
    expect(GROUNDING_TRITON.physics.closureValue).toBe(10);
    expect(GROUNDING_TRITON.moonshine.closureValue).toBe(10);
  });

  it('snapshot witnesses triple agreement', () => {
    const snap = groundingTritonSnapshot();
    expect(snap.tripleAgreement).toBe(true);
    expect(snap.nodes.length).toBe(3);
    expect(snap.triplePoint.closureValue).toBe(10);
    expect(snap.triplePoint.sharedUnit).toBe(1);
  });
});

describe('MonsterCache — closure tower', () => {
  it('caches closureChain values 10, 30, 90, 270, 810', () => {
    const cache = new MonsterCache();
    expect(cache.closureChain(0)).toBe(10);
    expect(cache.closureChain(1)).toBe(30);
    expect(cache.closureChain(2)).toBe(90);
    expect(cache.closureChain(3)).toBe(270);
    expect(cache.closureChain(4)).toBe(810);
  });

  it('extends lazily on demand', () => {
    const cache = new MonsterCache(2);
    expect(cache.depth()).toBe(2);
    cache.closureChain(10);
    expect(cache.depth()).toBeGreaterThanOrEqual(11);
  });

  it('recognizes closure points via isClosurePoint', () => {
    const cache = new MonsterCache();
    expect(cache.isClosurePoint(10)).toBe(true);
    expect(cache.isClosurePoint(30)).toBe(true);
    expect(cache.isClosurePoint(90)).toBe(true);
    expect(cache.isClosurePoint(270)).toBe(true);
    expect(cache.isClosurePoint(810)).toBe(true);
  });

  it('rejects non-closure values', () => {
    const cache = new MonsterCache();
    expect(cache.isClosurePoint(11)).toBe(false);
    expect(cache.isClosurePoint(20)).toBe(false);
    expect(cache.isClosurePoint(100)).toBe(false);
  });

  it('rejects values below the Pleromatic Closure', () => {
    const cache = new MonsterCache();
    expect(cache.isClosurePoint(0)).toBe(false);
    expect(cache.isClosurePoint(3)).toBe(false);
    expect(cache.isClosurePoint(9)).toBe(false);
  });

  it('returns the correct closure index', () => {
    const cache = new MonsterCache();
    expect(cache.closureIndexOf(10)).toBe(0);
    expect(cache.closureIndexOf(30)).toBe(1);
    expect(cache.closureIndexOf(90)).toBe(2);
    expect(cache.closureIndexOf(270)).toBe(3);
    expect(cache.closureIndexOf(810)).toBe(4);
    expect(cache.closureIndexOf(11)).toBe(-1);
  });
});

describe('FRF — Fork/Race/Fold scale-invariant engine', () => {
  it('fork at residue 0 is the Triton-stretch', () => {
    expect(FRF.fork(10, 0)).toBe(30);
    expect(FRF.fork(30, 0)).toBe(90);
    expect(FRF.fork(90, 0)).toBe(270);
    expect(FRF.tritonStretch(10)).toBe(30);
  });

  it('fork distinguishes residues 0, 1, 2', () => {
    expect(FRF.fork(10, 0)).toBe(30);
    expect(FRF.fork(10, 1)).toBe(31);
    expect(FRF.fork(10, 2)).toBe(32);
  });

  it('fold inverts fork-at-0', () => {
    expect(FRF.fold(FRF.fork(10, 0))).toBe(10);
    expect(FRF.fold(FRF.fork(30, 0))).toBe(30);
  });

  it('fold recovers base from any residue', () => {
    expect(FRF.fold(FRF.fork(10, 0))).toBe(10);
    expect(FRF.fold(FRF.fork(10, 1))).toBe(10);
    expect(FRF.fold(FRF.fork(10, 2))).toBe(10);
  });

  it('iteratedFold descends closures to grounding', () => {
    expect(FRF.iteratedFold(0, 10)).toBe(10);
    expect(FRF.iteratedFold(1, 30)).toBe(10);
    expect(FRF.iteratedFold(2, 90)).toBe(10);
    expect(FRF.iteratedFold(3, 270)).toBe(10);
    expect(FRF.iteratedFold(4, 810)).toBe(10);
  });

  it('race operationally equals fork', () => {
    expect(FRF.race(10, 0)).toBe(FRF.fork(10, 0));
    expect(FRF.race(10, 1)).toBe(FRF.fork(10, 1));
    expect(FRF.race(10, 2)).toBe(FRF.fork(10, 2));
  });
});

describe('SovereignJudge — Observing-mode validation', () => {
  it('accepts closure-tower positions', () => {
    const judge = new SovereignJudge();
    expect(judge.isValidPosition(10)).toBe(true);
    expect(judge.isValidPosition(30)).toBe(true);
    expect(judge.isValidPosition(90)).toBe(true);
    expect(judge.isValidPosition(270)).toBe(true);
  });

  it('rejects non-closure values', () => {
    const judge = new SovereignJudge();
    expect(judge.isValidPosition(11)).toBe(false);
    expect(judge.isValidPosition(100)).toBe(false);
    expect(judge.isValidPosition(7)).toBe(false);
  });

  it('verifies descent from 10 in 0 steps', () => {
    const judge = new SovereignJudge();
    const v = judge.verifyDescent(10);
    expect(v.valid).toBe(true);
    expect(v.foldSteps).toBe(0);
    expect(v.terminal).toBe(10);
    expect(v.isGroundingTriton).toBe(true);
    expect(v.closureIndex).toBe(0);
  });

  it('verifies descent from 30 in 1 step', () => {
    const judge = new SovereignJudge();
    const v = judge.verifyDescent(30);
    expect(v.valid).toBe(true);
    expect(v.foldSteps).toBe(1);
    expect(v.terminal).toBe(10);
    expect(v.isGroundingTriton).toBe(true);
    expect(v.closureIndex).toBe(1);
  });

  it('verifies descent from 270 in 3 steps', () => {
    const judge = new SovereignJudge();
    const v = judge.verifyDescent(270);
    expect(v.valid).toBe(true);
    expect(v.foldSteps).toBe(3);
    expect(v.terminal).toBe(10);
    expect(v.isGroundingTriton).toBe(true);
  });

  it('rejects descent for invalid (non-closure) positions', () => {
    const judge = new SovereignJudge();
    const v = judge.verifyDescent(11);
    expect(v.valid).toBe(false);
    expect(v.foldSteps).toBe(-1);
    expect(v.isGroundingTriton).toBe(false);
    expect(v.closureIndex).toBe(-1);
  });
});

describe('CostLedger — asymmetry of effort', () => {
  it('ascent cost = 2 × closure value', () => {
    expect(CostLedger.ascentCost(10)).toBe(20);
    expect(CostLedger.ascentCost(30)).toBe(60);
    expect(CostLedger.ascentCost(90)).toBe(180);
    expect(CostLedger.ascentCost(270)).toBe(540);
  });

  it('descent cost is always 0', () => {
    expect(CostLedger.descentCost()).toBe(0);
  });

  it('ascent cost triples per level', () => {
    expect(CostLedger.ascentCost(30)).toBe(3 * CostLedger.ascentCost(10));
    expect(CostLedger.ascentCost(90)).toBe(3 * CostLedger.ascentCost(30));
    expect(CostLedger.ascentCost(270)).toBe(3 * CostLedger.ascentCost(90));
  });

  it('cumulative ascent from grounding', () => {
    expect(CostLedger.cumulativeAscentCost(10)).toBe(0); // already there
    expect(CostLedger.cumulativeAscentCost(30)).toBe(20);
    expect(CostLedger.cumulativeAscentCost(90)).toBe(80);
    expect(CostLedger.cumulativeAscentCost(270)).toBe(260);
    expect(CostLedger.cumulativeAscentCost(810)).toBe(800);
  });
});
